import { z } from 'zod';

// Traefik schemas
export const SetupTraefikSchema = z.object({
  serverId: z.string().uuid(),
  email: z.string().email(),
});

// Custom UUID validator that accepts both standard UUIDs and prefixed UUIDs (stack-, deploy-)
const uuidOrPrefixedUuid = () =>
  z.string().refine(
    (val) => {
      const standardUuidRegex = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[1-8][0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$/;
      const prefixedUuidRegex = /^(stack|deploy)-[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[1-8][0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$/;
      return standardUuidRegex.test(val) || prefixedUuidRegex.test(val);
    },
    { message: 'Invalid UUID or prefixed UUID format' }
  );

export const ConfigureTraefikDomainSchema = z.object({
  serverId: z.string().uuid(),
  deploymentId: uuidOrPrefixedUuid().optional(),
  stackId: uuidOrPrefixedUuid().optional(),
  domain: z.string().min(3).max(255),
  port: z.number().int().min(1).max(65535),
  hostPort: z.number().int().min(1).max(65535).optional(),
  ssl: z.boolean().default(true),
  httpsRedirect: z.boolean().default(true),
  wwwRedirect: z.boolean().default(true),
  customHeaders: z.record(z.string(), z.string()).optional(),
});

// Security headers configuration
export const SecurityHeadersSchema = z.object({
  hstsEnabled: z.boolean().optional(),
  hstsMaxAge: z.number().int().min(0).optional(),
  hstsIncludeSubdomains: z.boolean().optional(),
  hstsPreload: z.boolean().optional(),
  xFrameOptions: z.enum(['DENY', 'SAMEORIGIN', '']).optional(),
  xContentTypeOptions: z.boolean().optional(),
  xXssProtection: z.boolean().optional(),
  referrerPolicy: z.enum(['no-referrer', 'no-referrer-when-downgrade', 'origin', 'origin-when-cross-origin', 'same-origin', 'strict-origin', 'strict-origin-when-cross-origin', 'unsafe-url', '']).optional(),
  contentSecurityPolicy: z.string().optional(),
});

// Basic auth user
export const BasicAuthUserSchema = z.object({
  username: z.string().min(1),
  password: z.string().min(1),
});

export const UpdateDomainSchema = z.object({
  domainId: z.string().uuid(),
  port: z.number().int().min(1).max(65535).optional(),
  ssl: z.boolean().optional(),
  httpsRedirect: z.boolean().optional(),
  wwwRedirect: z.boolean().optional(),
  customHeaders: z.record(z.string(), z.string()).optional(),
  // When true, auto-update PORT env var and port mapping in docker-compose.yml, then redeploy
  // Used when the user confirms they want to change the app's listening port
  forceRedeploy: z.boolean().optional(),
  // Security headers
  securityHeaders: SecurityHeadersSchema.optional(),
  // Rate limiting
  rateLimitEnabled: z.boolean().optional(),
  rateLimitAverage: z.number().int().min(1).optional(),
  rateLimitBurst: z.number().int().min(1).optional(),
  // Basic authentication
  basicAuthEnabled: z.boolean().optional(),
  basicAuthUsers: z.array(BasicAuthUserSchema).optional(),
  // IP whitelist
  ipWhitelistEnabled: z.boolean().optional(),
  ipWhitelist: z.array(z.string()).optional(),
});

export const DeleteDomainSchema = z.object({
  domainId: z.string().uuid(),
});

export const ServerIdOnlySchema = z.object({
  serverId: z.string().uuid(),
});

export const GetCertificateInfoSchema = z.object({
  serverId: z.string().uuid(),
  domain: z.string(),
});

export const GetTraefikLogsSchema = z.object({
  serverId: z.string().uuid(),
  lines: z.number().int().positive().default(100).optional(),
});

export const UpdateTraefikEmailSchema = z.object({
  serverId: z.string().uuid(),
  email: z.string().email(),
});

// ============ Security Schemas ============

// fail2ban schemas
export const Fail2BanConfigSchema = z.object({
  serverId: z.string(),
  enabled: z.boolean(),
  banTime: z.number().min(60).max(604800), // 1 minute to 1 week
  findTime: z.number().min(60).max(86400), // 1 minute to 1 day
  maxRetry: z.number().min(1).max(20),
  whitelistIPs: z.array(z.string()),
});

export const Fail2BanUnbanSchema = z.object({
  serverId: z.string(),
  ip: z.string(),
  jail: z.string().default('sshd'),
});

export const Fail2BanWhitelistSchema = z.object({
  serverId: z.string(),
  ips: z.array(z.string()),
});

// UFW Firewall schemas
export const UFWRuleSchema = z.object({
  serverId: z.string(),
  action: z.enum(['allow', 'deny', 'reject', 'limit']),
  port: z.string().regex(/^\d+(-\d+)?$/),
  protocol: z.enum(['tcp', 'udp', 'any']).default('tcp'),
  from: z.string().optional(),
  comment: z.string().optional(),
});

export const UFWDeleteRuleSchema = z.object({
  serverId: z.string(),
  ruleNumber: z.number().int().positive(),
});

export const UFWSetDefaultSchema = z.object({
  serverId: z.string(),
  direction: z.enum(['incoming', 'outgoing']),
  policy: z.enum(['allow', 'deny', 'reject']),
});

// SSH Hardening schemas
export const SSHConfigSchema = z.object({
  serverId: z.string(),
  permitRootLogin: z.boolean(),
  passwordAuthentication: z.boolean(),
  permitEmptyPasswords: z.boolean(),
  maxAuthTries: z.number().min(1).max(10),
  port: z.number().min(1).max(65535),
});

export const SSHPortChangeSchema = z.object({
  serverId: z.string(),
  currentPort: z.number().min(1).max(65535),
  newPort: z.number().min(1).max(65535),
});

export const SSHTestUsernameSchema = z.object({
  serverId: z.string(),
  username: z.string().min(1),
});

// Auto Updates schemas
export const AutoUpdatesConfigSchema = z.object({
  serverId: z.string(),
  enabled: z.boolean(),
  securityOnly: z.boolean(),
  autoReboot: z.boolean(),
  rebootTime: z.string().regex(/^\d{2}:\d{2}$/), // HH:MM format
});

// Security Audit schema
export const SecurityAuditSchema = z.object({
  serverId: z.string(),
});

// User Management schemas
export const UserListSchema = z.object({
  serverId: z.string(),
});

export const UserCreateSchema = z.object({
  serverId: z.string(),
  username: z.string().min(1).max(32).regex(/^[a-z_][a-z0-9_-]*[$]?$/, 'Invalid username format'),
  withSudo: z.boolean(),
  passwordMode: z.enum(['generate', 'set', 'none']),
  password: z.string().min(8).optional(),
});

export const UserDeleteSchema = z.object({
  serverId: z.string(),
  username: z.string().min(1),
  removeHome: z.boolean().default(false),
});

export const UserAddKeySchema = z.object({
  serverId: z.string(),
  username: z.string().min(1),
  publicKey: z.string().min(1),
});

export const UserListKeysSchema = z.object({
  serverId: z.string(),
  username: z.string().min(1),
});

export const UserRemoveKeySchema = z.object({
  serverId: z.string(),
  username: z.string().min(1),
  keyIndex: z.number().int().nonnegative(),
});

// ============ Security Type Exports ============

export type Fail2BanConfigInput = z.infer<typeof Fail2BanConfigSchema>;
export type Fail2BanUnbanInput = z.infer<typeof Fail2BanUnbanSchema>;
export type Fail2BanWhitelistInput = z.infer<typeof Fail2BanWhitelistSchema>;
export type UFWRuleInput = z.infer<typeof UFWRuleSchema>;
export type UFWDeleteRuleInput = z.infer<typeof UFWDeleteRuleSchema>;
export type UFWSetDefaultInput = z.infer<typeof UFWSetDefaultSchema>;
export type SSHConfigInput = z.infer<typeof SSHConfigSchema>;
export type SSHPortChangeInput = z.infer<typeof SSHPortChangeSchema>;
export type SSHTestUsernameInput = z.infer<typeof SSHTestUsernameSchema>;
export type AutoUpdatesConfigInput = z.infer<typeof AutoUpdatesConfigSchema>;
export type SecurityAuditInput = z.infer<typeof SecurityAuditSchema>;
export type UserListInput = z.infer<typeof UserListSchema>;
export type UserCreateInput = z.infer<typeof UserCreateSchema>;
export type UserDeleteInput = z.infer<typeof UserDeleteSchema>;
export type UserAddKeyInput = z.infer<typeof UserAddKeySchema>;
export type UserListKeysInput = z.infer<typeof UserListKeysSchema>;
export type UserRemoveKeyInput = z.infer<typeof UserRemoveKeySchema>;

export interface SSHPortChangeResult {
  success: boolean;
  message: string;
  needsManualRecovery?: boolean;
}

// Security status interfaces
export interface Fail2BanStatus {
  installed: boolean;
  running: boolean;
  jails: string[];
  sshJail: {
    enabled: boolean;
    currentlyBanned: number;
    totalBanned: number;
    bannedIPs: string[];
  };
  config?: {
    banTime: number;
    findTime: number;
    maxRetry: number;
    whitelistIPs: string[];
  };
}

export interface UFWRule {
  number: number;
  action: 'ALLOW' | 'DENY' | 'REJECT' | 'LIMIT';
  direction: 'IN' | 'OUT';
  protocol: 'tcp' | 'udp' | 'any';
  port: string;
  from: string;
  to: string;
  comment?: string;
}

export interface UFWStatus {
  installed: boolean;
  enabled: boolean;
  defaultIncoming: 'allow' | 'deny' | 'reject';
  defaultOutgoing: 'allow' | 'deny' | 'reject';
  rules: UFWRule[];
}

export interface SSHStatus {
  permitRootLogin: boolean;
  passwordAuthentication: boolean;
  permitEmptyPasswords: boolean;
  maxAuthTries: number;
  port: number;
  score: number;
  issues: string[];
}

export interface AutoUpdatesStatus {
  installed: boolean;
  enabled: boolean;
  securityOnly: boolean;
  autoReboot: boolean;
  rebootTime: string;
  pendingUpdates: number;
  lastCheckTime: string | null;
  recentActivity: Array<{
    date: string;
    message: string;
    success: boolean;
  }>;
}

export interface SecurityAuditResult {
  overallScore: number;
  fail2ban: {
    score: number;
    status: 'running' | 'stopped' | 'not_installed';
    bannedCount: number;
  };
  firewall: {
    score: number;
    status: 'active' | 'inactive' | 'not_installed';
    rulesCount: number;
  };
  ssh: {
    score: number;
    issues: string[];
  };
  updates: {
    score: number;
    enabled: boolean;
    pendingCount: number;
  };
  recommendations: Array<{
    type: 'warning' | 'info';
    message: string;
    action: string;
  }>;
}

// User Management Interfaces
export interface UserInfo {
  username: string;
  uid: number;
  homeDir: string;
  shell: string;
  hasSudo: boolean;
  sshKeyCount: number;
}

export interface UserSSHKey {
  index: number;
  type: string;
  fingerprint: string;
  comment: string;
}

export interface CreateUserResult {
  generatedPassword?: string;
}

